import{_ as e,o as a,c as t,ak as _}from"./chunks/framework.BwREiRwV.js";const m=JSON.parse('{"title":"第八章 三次半拍","description":"","frontmatter":{},"headers":[],"relativePath":"永恒道途/正文/第一卷-山门有路/第八章-三次半拍.md","filePath":"永恒道途/正文/第一卷-山门有路/第八章-三次半拍.md"}'),r={name:"永恒道途/正文/第一卷-山门有路/第八章-三次半拍.md"};function o(n,p,s,c,i,d){return a(),t("div",null,[...p[0]||(p[0]=[_('<h1 id="第八章-三次半拍" tabindex="-1">第八章 三次半拍 <a class="header-anchor" href="#第八章-三次半拍" aria-label="Permalink to &quot;第八章 三次半拍&quot;">​</a></h1><p>青云宗外门岁试，在仲秋第一日开场。</p><p>所谓岁试，是外门弟子每年一次的排名考核。有人靠它赚取贡献，有人借机进入执事视线，也有人只想知道自己这一年究竟有没有白过。久而久之，弟子们都把它叫作外门大比。</p><p>晨钟未绝，外门演武场已是人山人海。</p><p>十二座青石擂台沿山势层层排开，擂边阵纹微亮，能挡炼气修士误伤。看台上吵声如潮，押注、喝彩、咒骂混在一起，热得像一口沸锅。</p><p>“丁字擂今天最热，赵魁在那边！”</p><p>“听说药园有个新冒头的，也在丁字。”</p><p>“药园的？那不是送分？”</p><p>陈玄站在药园队列最末，灰衣朴素，手里只握一块木号牌。他没看四周，只把呼吸压到最平，等执事唱名。</p><p>腰间那柄剑是他三日前从坊市买来的青铁剑，凡铁中掺了少许青纹矿，谈不上法器，却比柴刀更适合灵力通行。为了买它，他花掉三块灵石，还欠了王胖子半块。</p><p>剑未经血，也没有名字。</p><p>陈玄昨夜把基础十三式各练了五百遍，今日第一次用它面对真正的修士。</p><p>执事宣读规则时，他听得很仔细：落出白线、失去战力或主动认输皆算落败；不得使用二阶以上符箓，不得故意取人性命；刀剑无眼，重伤由参赛者自负。</p><p>最后一条落下，喧闹的演武场似乎也冷了几分。</p><p>“丁字七号擂，第一轮，陈玄对赵魁。”</p><p>话音一落，四周起哄声更大。</p><p>赵魁，外门出名的炼体修士，炼气四层巅峰，力大皮厚，手里那根黑木棍常被人叫“断骨棍”。不少同阶不是被他一棍扫出界，就是被他硬生生撞崩护体灵光。</p><p>赵魁扛棍上台，见陈玄身形清瘦，咧嘴一笑：“药园来的？自己下去，省得我收不住力。”</p><p>陈玄拔出青铁剑，没接话。</p><p>赵魁说话狂，却没有在擂钟前抢攻。他双手握棍，前脚微屈，重心压得很稳。只看起势便知道，此人绝非只靠蛮力走到今日。</p><p>陈玄在台下看过赵魁两场旧战记录。对方前三棍最重，十棍之后换气会慢；右肩曾被妖兽咬伤，横扫无碍，向上回棍时却总会略低半寸。</p><p>知道破绽，不代表能抓住破绽。</p><p>擂钟一响，赵魁先动。</p><p>黑木棍抡出一圈乌影，棍风扫过地面，带起一串火星。陈玄不硬接，连退两步，借半身位切向赵魁右侧，剑尖连点肘弯与膝侧。</p><p>“叮！叮！”</p><p>剑锋点在对方筋骨处，像敲在铁上。</p><p>反震顺剑身传回，陈玄虎口当即发麻。他第二剑本想点赵魁右肩，黑木棍却比预想中回得更快，棍梢擦过胸前护身灵光，震得那层薄光剧烈摇晃。</p><p>再重一分，护身符便会破。</p><p>看台顿时哄笑。</p><p>“挠痒呢？”</p><p>“这小子破不了防！”</p><p>陈玄神色不变，继续游走。他很清楚，这一战若拼硬碰硬，三招内就会被碾碎。唯一的解法，是拖，拖到赵魁那股爆发劲往下掉。</p><p>十余息后，赵魁连挥八棍，呼吸果然粗了半拍。陈玄立刻压上，剑尖斜挑赵魁腕骨。赵魁吃痛，棍势一滞。陈玄抓住空档贴身撞进中门，脚下一绊，肩背发力。</p><p>赵魁并未像预计中立刻失衡。他沉腰顶住，左肘狠狠砸向陈玄后颈。</p><p>陈玄若退，先前好不容易换来的贴身位置便会丢掉。他咬牙承下这一肘，眼前瞬间一黑，右脚却已经勾住赵魁脚踝。与此同时，他把剩余灵力尽数压进肩头，顺着对方发力方向向前一送。</p><p>轰的一声闷响，赵魁整个人失衡后仰，连退两步，踩出白线。</p><p>“丁字七号擂，陈玄胜！”</p><p>第一战，过。</p><p>陈玄走下擂台时，后颈火辣，右耳里全是沉闷嗡鸣。他没有因看台叫好便回头，只在药园棚下坐定，重新回想赵魁最后那记肘击。</p><p>计划只能让人占先，不能让对手照着计划走。若赵魁方才不想着把他砸倒，而是先退一步稳住白线，这场胜负还要继续。</p><p>药园看台上爆出几声压着兴奋的叫好，连鲁老头都狠狠拍了下大腿：“好小子，懂得用脑！”</p><p>韩执事站在后方，脸上仍无表情，只淡淡丢下一句：“别高兴太早，下一轮会更脏。”</p><p>午后第二轮，陈玄对周宁。</p><p>周宁同为炼气四层，符修，最擅火符连爆，一上台就先掏符袋，显然没打算让陈玄近身。</p><p>“听说你步法快。”周宁冷笑，“我看你能在火里跑多久。”</p><p>陈玄看向他脚边。</p><p>周宁的符袋挂在左腰，脚下却站在擂台西侧。午后山风自西向东，火势顺风，陈玄若一味躲闪，只会被逼去东角。</p><p>这是对方提前选好的局。</p><p>擂钟未落，三张火球符已先后点燃。</p><p>赤焰翻卷，热浪扑脸。陈玄在火缝中侧步急闪，衣袖还是被擦开一角，焦糊味立刻弥开。</p><p>周宁越打越急，符光一道接一道，把陈玄逼在擂台东角。看台有人大喊：“再来两张！烧他下去！”</p><p>火浪一层压着一层。陈玄眉梢被燎去少许，左臂衣料与皮肉黏在一起，吸气时喉间都是焦苦味。</p><p>第六张符炸开后，东角已经没有退路。</p><p>周宁眼中闪过喜色，右手探进符袋，摸向那张威力最大的连珠火符。</p><p>陈玄却始终没乱。</p><p>符修的长处是爆发，短处是续力。周宁每次掷符前，指诀与吐息都会慢半拍，那就是破口。</p><p>第七张火符脱手时，陈玄脚下一折，借爆焰卷起的烟尘贴地突进。周宁只来得及抬臂护喉，剑背已重重砸在他腕骨上，整包符纸散落一地。</p><p>那些符纸落在尚未熄灭的火星旁，周宁脸色骤变，本能弯腰去抢。</p><p>他一弯腰，中门便彻底空了。</p><p>下一瞬，青铁剑尖抵在周宁喉前三寸。</p><p>“我认输！”</p><p>第二战，再胜。</p><p>周宁收符时脸色难看，却仍走到陈玄面前：“你前面一直在数我的符？”</p><p>“你的连珠火符画在黄纸上，袋里只有一张。”</p><p>“所以你故意退到东角，等我以为能收场？”</p><p>陈玄没有否认。</p><p>周宁沉默片刻，抱拳离开。输给境界高的人容易接受，输给一个从第一张符便开始算自己的人，却会让人很久忘不掉。</p><p>看台议论立刻变了味。</p><p>“这药园弟子有点邪门，专抓节奏缝。”</p><p>“不是邪门，是稳。两场都先挨压再反打。”</p><p>“这种人进淘汰赛会很麻烦。”</p><p>陈玄下台时，韩执事把一个小瓷瓶扔给他：“止血散。你左臂烫伤，别硬撑。”</p><p>陈玄接住，点头道谢。</p><p>韩执事目光在他脸上停了半息，声音依旧冷：“第三场抽到炼气五层概率很高。你若怕，现在还能弃赛。”</p><p>“不弃。”陈玄道。</p><p>傍晚第三轮抽签。</p><p>“庚字二号擂，陈玄，对许沉。”</p><p>许沉，炼气五层，外门老弟子，修《裂石掌》，掌力沉猛，擂台经验足。签名一出，看台押注牌几乎一边倒，全压许沉。</p><p>王胖子不知何时混进人群，站在栏边咬牙：“陈兄弟，你今天别逞强，能拖就拖……”</p><p>话没说完，擂钟已响。</p><p>许沉踏步如锤，第一掌就逼得陈玄横剑硬挡。掌劲顺剑传来，震得他虎口发麻，胸口气血翻涌，喉头泛起一丝腥甜。</p><p>境界差距，摆在眼前。</p><p>许沉不给喘息，第二掌、第三掌连成一线，掌影铺开像一堵墙，逼着陈玄一路退到擂台边角。看台上摇头声此起彼伏。</p><p>第三掌落下时，青铁剑发出不堪重负的颤鸣。陈玄右臂经脉像被震开，半边手掌失去知觉。</p><p>他终于明白，炼气五层与四层之间不只差一成灵力。对方的灵力更凝实，护体也更完整，自己前两场依赖的贴身抢位，一旦被正面掌力压住便无从施展。</p><p>“到头了。”</p><p>“炼气四层终究是炼气四层。”</p><p>陈玄却在后退中越发清醒。</p><p>许沉的掌法强在正面碾压，弱在收掌换步那半拍。前两场他一直没用尽的“折云步”变线，就是等这一刻。</p><p>许沉第四掌压下，陈玄不退反进，脚下一错，整个人几乎擦着掌风切入肘下死角。青铁剑横转，不劈不刺，以剑脊狠狠砸向膻中。</p><p>这一变线并不漂亮。</p><p>许沉掌风仍擦中陈玄左肩，把他整个人带得旋转半圈。肩骨传来一声轻响，剧痛让剑势几乎散掉。陈玄顺着旋转之力沉腰，剑脊才从一个极低的角度撞中膻中。</p><p>“砰！”</p><p>许沉胸口一窒，气机断了半拍。</p><p>半拍已够。</p><p>陈玄连出三剑，点腕、压肩、扫膝，逼得许沉重心后仰。许沉怒喝提灵再冲，陈玄却已转到侧后，剑柄重击后颈，把人打得踉跄跪地。</p><p>许沉单膝触地，反手便是一掌。陈玄早有防备，横剑架住，仍被掌力推出六步。两人同时停在白线前，一人胸口气息难续，一人左臂垂落，谁也没有立刻倒下。</p><p>许沉深吸气，想再次起身，膻中被截断的灵力却在此时逆冲。他脸色骤红，张口吐出一口血。</p><p>裁判执事立刻喝止：“点到为止！”</p><p>许沉撑地喘了几口粗气，抬头看向陈玄，眼底不甘翻涌，终究还是抱拳：“我输了。”</p><p>庚字擂先静一息，随即轰然炸响。</p><p>一个炼气四层的药园弟子，三战全胜，还越境拿下炼气五层，足够让全场记住名字。</p><p>“陈玄！”</p><p>“药园黑马！”</p><p>“这人有点狠！”</p><p>日落时，第一日赛程收官。</p><p>喧声散去后，疼痛才变得清晰。</p><p>陈玄左肩轻微错位，韩执事替他正骨时只说了一句“忍着”，下一瞬便将骨头推回原处。咔的一声，陈玄额头冷汗立刻滚了下来，咬住的布条几乎被牙齿磨断。</p><p>鲁老头在旁边骂：“三块灵石买的破剑，差点让人一掌震断。明日若再上台，先看看胳膊还听不听使唤。”</p><p>“能抬。”</p><p>“抬得起来和挥得出剑是两回事。”</p><p>陈玄试着握拳。指尖仍麻，至少经脉没有真正断裂。</p><p>陈玄站在榜墙前，看见自己名字后多了三个字：晋三十二。</p><p>这意味着，他已提前锁定外门前三十二，拿到十点贡献与一次藏经阁一层入阁资格。</p><p>韩执事把木牌递给他，语气仍硬：“运气不错。后面淘汰赛更狠，别把今天当本事。”</p><p>“弟子明白。”</p><p>回木屋的山道上，王胖子气喘吁吁追上来，捂着钱袋子一脸肉疼：“我押你前两场都中，第三场手贱压了许沉，白亏三块灵石！”</p><p>陈玄瞥他一眼：“你活该。”</p><p>胖子捶胸顿足，下一刻又凑近低声道：“不过你这场真值。藏经阁机会可不是天天有，赶紧去挑门狠的。再靠基础剑招，你撑不到后面。”</p><p>陈玄点头，没有反驳。</p><p>他比谁都清楚，今天能赢，靠的是算计、耐性和硬扛，不是绝对实力。若没有更高层次的剑诀，下一轮遇到真正的外门强手，他很可能十招都撑不过。</p><p>夜色压下，演武场喧嚣渐远。</p><p>陈玄回到木屋，把那枚“藏经阁入阁令”放在掌心，静静看了许久。</p><p>木牌很薄，很轻。</p><p>却像一把钥匙，正要撬开他真正的剑修之路。</p><p>他没有立刻翻看王胖子送来的热门功法名录，而是把今日三名对手分别写在纸上。赵魁败在换气，周宁败在符数，许沉败在气机被截断；而他每一场也都只差一步便会落败。</p><p>三战全胜不是同阶无敌，只是三次判断比对手快了半拍。</p><p>陈玄把纸折好，放进《山药札记》。这些胜负得失，和父亲记下的药性一样，日后都会成为能救命的东西。</p><p>（第八章完）</p>',129)])])}const f=e(r,[["render",o]]);export{m as __pageData,f as default};
